class Solution {
    public long minimumSteps(String s) {
        int blackCount = 0;
        for (char c : s.toCharArray()) {
            if (c == '1') {
                blackCount++;
            }
        }
        return Math.max(0, blackCount * (s.length() - blackCount));
    }
}
